VALUES
  ('dietitian-moex-04154', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關糖尿病的飲食原則，下列何者最不適當？', '["減重有助於改善血糖控制，對於肥胖糖尿病人，營養師應聚焦於以減重為中心的飲食計畫", "第1型糖尿病的青少年，應定期追蹤其生長及發育，嚴格飲食限制來預防肥胖可能會導致飲食失調 的發展", "應符合個人及文化的偏好，鼓勵病人選擇合適份量的健康食物", "提供多樣性食物選擇來維持飲食的樂趣"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04155', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關妊娠糖尿病的照護，下列敘述何者最適當？', '["空腹血糖控制目標＜120 mg/dL", "醣類食物要分配至3餐與2～4份點心", "應避免餵母乳以減少新生兒罹病風險", "糖化血色素控制目標＜5.6%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04156', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關糖尿病之黎明現象（dawn phenomenon），下列敘述何者正確？', '["是半夜低血糖後在黎明時反彈的現象", "此現象起源於低血糖時分泌反調節荷爾蒙的結果", "是黎明前胰島素減少或夜間肝臟葡萄糖產生過多所致", "可減少晚上胰島素劑量或改長效胰島素避免此現象發生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04157', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列有關預防腎結石復發的敘述，何者最不適當？', '["發炎性腸道疾病（inflammatory bowel disease）會增加草酸鈣結石的發生率", "酸性尿液（low urine pH）是導致尿酸腎結石的重要原因", "預防胱胺酸結石（cystine stone）復發，每日水分攝取量需要超過4公升以上", "鹼化尿液（raising urine pH）可以預防磷酸氨鎂結石（struvite stone）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04158', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '劉先生，170公分，76公斤，糖尿病腎病變病人，其血液生化值如下（括弧內數值為正常值範 圍）：HbA1c 9.7%、BUN 47（7～20）mg/dL、creatinine 2.1（0.5～1.3）mg/dL、potassium 5.5 （3.5～5.5）mEq/L、phosphorus 4.8（2.3～5.1）mg/dL、血壓150/98 mmHg，有關劉先生的治療 建議，下列何者最不適當？', '["良好血糖控制對延緩腎功能惡化的影響大於降低蛋白質的攝取量", "血壓控制好對延緩腎功能惡化的影響大於降低蛋白質的攝取量", "維持血磷正常可以延緩副甲狀腺亢進與骨病變發生", "此時使用得舒飲食（DASH diet）能延緩腎功能喪失速度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04159', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '蔡先生是規律血液透析的病人，下列何種維生素最不易在透析時流失？', '["維生素B 12", "維生素B 6", "維生素C", "葉酸"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04160', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關醫師評估透析病人乾體重（dry weight）的目的，下列何者錯誤？', '["維持體內最佳體液容積", "維持正常血壓", "減少蛋白尿", "降低死亡率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04161', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '依據美國心臟協會（American Heart Association）和美國心臟醫學會（American College of Cardiology）於2018年所提出的飲食減鈉指引，下列何者錯誤？', '["血壓偏高的成年人應將每日鈉攝取量減至1,500 mg以下", "血壓正常的成年人每日不宜攝取超過6 g的鹽", "高血壓病人應將每日鈉攝取量控制在1,000 mg以下", "多數成年人應試著至少減少1,000 mg的每日鈉攝取量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04162', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列何種飲食成分與降低血清膽固醇濃度最無關？', '["plant stanols", "vitamin E", "nicotinic acid", "soluble fiber"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04163', 'dietitian', 'dietitian-moex-114-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '依據2013年美國心臟醫學會（American College of Cardiology）／美國心臟協會（American Heart Association）發表的臨床指引，下列何種運動型態最適合用於防治高血壓？', '["中至高強度的有氧運動，每週至少3～4次，平均每次40分鐘", "輕至中強度的有氧運動，每週至少3～4次，平均每次40分鐘", "中至高強度的有氧運動，每週至少3～4次，平均每次30分鐘", "輕至中強度的有氧運動，每週至少3～4次，平均每次30分鐘"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "b23ed10f357e", "answer_pdf_sha1": "bf3ea9b1b4d4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
